const input = $input.first();
const body = input.json.body || {};
const topic = (typeof body === 'object' ? body.topic : '') || input.json.topic || '';

if (!topic || topic.trim().length < 3) {
  throw new Error('No topic provided. POST JSON with topic field.');
}

const fs = require('fs');
const pathLib = require('path');
const publishedDir = '/home/node/output/my-media-helper/published';
let posts = [];
let historyText = '';

try {
  const files = fs.readdirSync(publishedDir).filter(f => f.endsWith('.md')).sort();
  for (const file of files) {
    const content = fs.readFileSync(pathLib.join(publishedDir, file), 'utf-8').trim();
    if (content) posts.push({ file, content });
  }
  if (posts.length > 0) {
    historyText = posts.map((p, i) => '--- Post ' + (i + 1) + ' (' + p.file + ') ---\n' + p.content).join('\n\n');
  }
} catch (e) {
  historyText = '';
}

return [{ json: { topic: topic.trim(), posts, historyText } }];

const data = $('Load History').first().json;
const topic = data.topic;
const historyText = data.historyText;

const historySection = historyText
  ? 'Published posts by this author. Match the voice, tone, and style exactly:\n\n' + historyText + '\n\n'
  : '';

const prompt = historySection
  + 'Write a LinkedIn post about this topic:\n\n'
  + topic
  + '\n\nVoice rules:\n- Direct and confident, no hedging or filler\n- Share specific details, tools, or numbers when relevant\n- Professional but conversational, not corporate or stiff\n- First person\n- Appropriate length for the content (can be short 3-5 lines or medium 10-15 lines)\n- Do not always end with a question or call to action\n- No AI-sounding phrases or excessive enthusiasm\n\nOutput only the post text, nothing else.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, topic, historyText } }];

const draft = $input.first().json.content[0].text;
const historyText = $('Load History').first().json.historyText;

const historySection = historyText
  ? 'Author published posts for reference:\n\n' + historyText + '\n\n'
  : '';

const prompt = historySection
  + 'Critically review this LinkedIn post draft:\n\n'
  + draft
  + '\n\nGive specific numbered feedback (max 8 points) on:\n- Does it match the author voice (direct, specific, not generic)?\n- Any phrases that sound AI-generated or corporate?\n- Is the content specific enough or too vague?\n- Is the structure and length appropriate for the content?\n- Any missed opportunities to add a real detail or perspective?\n\nBe direct and specific. Output only the numbered critique, nothing else.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, draft } }];

const critique = $input.first().json.content[0].text;
const draft = $('Critic Build').first().json.draft;

const prompt = 'Rewrite this LinkedIn post based on the critic feedback. Address each point. Keep what already works well.\n\nORIGINAL DRAFT:\n' + draft + '\n\nCRITIC FEEDBACK:\n' + critique + '\n\nOutput only the revised post text, nothing else.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, draft, critique } }];

const revised = $input.first().json.content[0].text;
const critique = $('Finetune Build').first().json.critique;
const draft = $('Finetune Build').first().json.draft;
const historyText = $('Load History').first().json.historyText;

const historySection = historyText
  ? 'Author history posts (check whether hashtags appear in them):\n\n' + historyText + '\n\n'
  : '';

const prompt = historySection
  + 'Format this post for LinkedIn publishing:\n\n'
  + revised
  + '\n\nFormatting rules:\n- Add blank lines between paragraphs for readability\n- Add hashtags at the end ONLY if the author uses hashtags in the history posts. If no hashtags appear in history, add none at all.\n- Keep under 3000 characters\n- Do not change the meaning, voice, or content\n\nOutput only the formatted post text, nothing else.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, revised, critique, draft } }];

const formatted = $input.first().json.content[0].text;
const revised = $('Prepare Build').first().json.revised;

const prompt = 'Final quality check for this LinkedIn post:\n\n'
  + formatted
  + '\n\nCheck: reads naturally (not AI-written), specific and authentic, no typos or awkward phrasing, LinkedIn-appropriate length and format.\n\nOutput format (strict):\nSTATUS: APPROVED\nor\nSTATUS: NEEDS REVISION: [one sentence why]\n\nThen on a new line:\nFINAL POST:\n[post text, with any corrections applied]';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, formatted, revised } }];

const finalResponse = $input.first().json.content[0].text;
const topic = $('Load History').first().json.topic;

const statusMatch = finalResponse.match(/STATUS:\s*(APPROVED|NEEDS REVISION[^\n]*)/i);
const status = statusMatch ? statusMatch[1].trim() : 'UNKNOWN';
const isApproved = status.startsWith('APPROVED');

const finalPostMatch = finalResponse.match(/FINAL POST:\s*([\s\S]+)/i);
const finalPost = finalPostMatch ? finalPostMatch[1].trim() : $('Final Check Build').first().json.formatted;

const draft = $('Critic Build').first().json.draft;
const critique = $('Finetune Build').first().json.critique;
const revised = $('Prepare Build').first().json.revised;
const formatted = $('Final Check Build').first().json.formatted;

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const dateLabel = new Date().toISOString().split('T')[0];

const markdown = '# LinkedIn Post Draft\n**Topic:** ' + topic + '\n**Date:** ' + dateLabel + '\n**Status:** ' + status + '\n\n## Final Post\n\n' + finalPost + '\n\n---\n\n## Agent Trail\n\n### 1. Draft\n' + draft + '\n\n### 2. Critic Feedback\n' + critique + '\n\n### 3. Revised\n' + revised + '\n\n### 4. Formatted\n' + formatted + '\n\n### 5. Final Check\n' + finalResponse + '\n';

const statusColor = isApproved ? '#22c55e' : '#f59e0b';
const statusBg = isApproved ? '#052e16' : '#1c1208';

const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>');

const html = '<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd">'
  + '<html xmlns="http://www.w3.org/1999/xhtml"><head>'
  + '<meta http-equiv="Content-Type" content="text/html; charset=utf-8">'
  + '<title>LinkedIn Draft</title></head>'
  + '<body style="margin:0; padding:0; background-color:#0a0f1a;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#0a0f1a;">'
  + '<tr><td align="center" style="padding:20px 0;">'
  + '<table width="660" cellpadding="0" cellspacing="0" border="0" style="max-width:660px; width:100%;">'
  + '<tr><td style="background-color:#0f1b2d; padding:36px 32px 28px 32px; border-bottom:3px solid #2563eb;">'
  + '<div style="font-size:12px; color:#60a5fa; text-transform:uppercase; letter-spacing:3px; font-weight:bold; margin-bottom:10px; font-family:Arial,sans-serif;">LinkedIn Draft</div>'
  + '<h1 style="color:#f1f5f9; font-size:22px; margin:0 0 8px 0; font-weight:bold; font-family:Arial,sans-serif;">' + esc(topic) + '</h1>'
  + '<div style="color:#94a3b8; font-size:13px; font-family:Arial,sans-serif;">' + dateLabel + '</div>'
  + '</td></tr>'
  + '<tr><td style="background-color:' + statusBg + '; padding:16px 32px; border-bottom:1px solid #1e3a5f;">'
  + '<span style="color:' + statusColor + '; font-family:Arial,sans-serif; font-size:14px; font-weight:bold;">&#9679; ' + esc(status) + '</span>'
  + '</td></tr>'
  + '<tr><td style="background-color:#111827; padding:28px 32px;">'
  + '<h2 style="color:#93c5fd; font-size:16px; margin:0 0 16px 0; font-family:Arial,sans-serif;">Final Post</h2>'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>'
  + '<td width="4" style="background-color:#2563eb;"></td>'
  + '<td style="padding:16px 20px; background-color:#0f1f38; font-family:Arial,sans-serif; font-size:14px; color:#e2e8f0; line-height:1.7;">' + esc(finalPost) + '</td>'
  + '</tr></table>'
  + '<br><h2 style="color:#93c5fd; font-size:16px; margin:24px 0 12px 0; font-family:Arial,sans-serif;">Critic Feedback</h2>'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>'
  + '<td width="4" style="background-color:#f59e0b;"></td>'
  + '<td style="padding:16px 20px; background-color:#1c1a0f; font-family:Arial,sans-serif; font-size:13px; color:#cbd5e1; line-height:1.6;">' + esc(critique) + '</td>'
  + '</tr></table>'
  + '</td></tr>'
  + '<tr><td style="background-color:#0a0f1a; padding:20px 32px; border-top:1px solid #1e3a5f; text-align:center; font-family:Arial,sans-serif;">'
  + '<div style="color:#64748b; font-size:12px;">my-media-helper</div>'
  + '</td></tr>'
  + '</table></td></tr></table></body></html>';

const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'draft-' + timestamp + '.md', 'text/markdown');

return [{ json: { markdown, html, finalPost, status, topic, timestamp }, binary: { data: binaryData } }];
